1	export type Item = {
2	  type: string;
3	  material?: string;
4	  enchantment?: number;
5	  cursed?: boolean;
6	};
7	
8	export type QuoteStep = {
9	  op: "quote";
10	  items: Item[];
11	};
12	
13	export type Step = QuoteStep;
14	
15	export type Scenario = {
16	  customer: { yearsWithMHPCO: number };
17	  steps: Step[];
18	};
19	
20	export type QuoteResult = { premium: number };
21	export type StepResult = QuoteResult;
22	
23	export type ScenarioResult = {
24	  results: StepResult[];
25	};
26	
27	const PROCESSING_FEE = 5;
28	const FIRST_CONTRACT_SURCHARGE_RATE = 0.1;
29	const FOLLOW_UP_CONTRACT_DISCOUNT_RATE = 0.15;
30	const BLOCK_OF_THREE_DISCOUNT = 15;
31	const CURSE_SURCHARGE_RATE = 0.5;
32	const HIGH_ENCHANTMENT_SURCHARGE_RATE = 0.3;
33	const HIGH_ENCHANTMENT_THRESHOLD = 5;
34	const LOYALTY_DISCOUNT_RATE = 0.2;
35	const LOYALTY_YEARS_THRESHOLD = 2;
36	
37	const BASE_PREMIUM: Record<string, number> = {
38	  sword: 100,
39	  amulet: 60,
40	  staff: 80,
41	  potion: 40,
42	  rune: 25,
43	  moonstone: 25,
44	};
45	
46	const BLOCK_OF_THREE_ELIGIBLE_TYPES = ["rune", "moonstone"];
47	
48	const blockOfThreeDiscount = (alikeComponentCount: number): number =>
49	  alikeComponentCount === 3 ? BLOCK_OF_THREE_DISCOUNT : 0;
50	
51	const countItemsOfType = (items: Item[], type: string): number =>
52	  items.filter((item) => item.type === type).length;
53	
54	const isCursed = (item: Item): boolean => item.cursed === true;
55	const isHighlyEnchanted = (item: Item): boolean =>
56	  (item.enchantment ?? 0) >= HIGH_ENCHANTMENT_THRESHOLD;
57	
58	const ITEM_SURCHARGE_RATES: ReadonlyArray<{
59	  applies: (item: Item) => boolean;
60	  rate: number;
61	}> = [
62	  { applies: isCursed, rate: CURSE_SURCHARGE_RATE },
63	  { applies: isHighlyEnchanted, rate: HIGH_ENCHANTMENT_SURCHARGE_RATE },
64	];
65	
66	const basePremiumFor = (item: Item): number => {
67	  if (!(item.type in BASE_PREMIUM)) {
68	    throw new Error(`Unknown item type: ${item.type}`);
69	  }
70	  return BASE_PREMIUM[item.type];
71	};
72	
73	const surchargesForItem = (item: Item): number => {
74	  const base = basePremiumFor(item);
75	  return ITEM_SURCHARGE_RATES.reduce(
76	    (sum, { applies, rate }) => sum + (applies(item) ? base * rate : 0),
77	    0,
78	  );
79	};
80	
81	const sumItemSpecificSurcharges = (items: Item[]): number =>
82	  items.reduce((sum, item) => sum + surchargesForItem(item), 0);
83	
84	const calculateBasePremium = (items: Item[]): number => {
85	  const subtotal = items.reduce((sum, item) => sum + basePremiumFor(item), 0);
86	  const totalDiscount = BLOCK_OF_THREE_ELIGIBLE_TYPES.reduce(
87	    (sum, type) => sum + blockOfThreeDiscount(countItemsOfType(items, type)),
88	    0,
89	  );
90	  return subtotal - totalDiscount;
91	};
92	
93	const firstContractSurcharge = (basePremium: number): number =>
94	  basePremium * FIRST_CONTRACT_SURCHARGE_RATE;
95	
96	const qualifiesForLoyaltyDiscount = (yearsWithMHPCO: number): boolean =>
97	  yearsWithMHPCO >= LOYALTY_YEARS_THRESHOLD;
98	
99	const loyaltyDiscount = (basePremium: number, yearsWithMHPCO: number): number =>
100	  qualifiesForLoyaltyDiscount(yearsWithMHPCO) ? basePremium * LOYALTY_DISCOUNT_RATE : 0;
101	
102	const followUpContractDiscount = (basePremium: number, priorQuoteCount: number): number =>
103	  priorQuoteCount > 0 ? basePremium * FOLLOW_UP_CONTRACT_DISCOUNT_RATE : 0;
104	
105	const quote = (
106	  step: QuoteStep,
107	  customer: Scenario["customer"],
108	  priorQuoteCount: number,
109	): QuoteResult => {
110	  const basePremium = calculateBasePremium(step.items);
111	  const itemSurcharges = sumItemSpecificSurcharges(step.items);
112	  const premium = Math.ceil(
113	    basePremium +
114	      itemSurcharges +
115	      firstContractSurcharge(basePremium) -
116	      loyaltyDiscount(basePremium, customer.yearsWithMHPCO) -
117	      followUpContractDiscount(basePremium, priorQuoteCount) +
118	      PROCESSING_FEE,
119	  );
120	  return { premium };
121	};
122	
123	export const runScenario = (scenario: Scenario): ScenarioResult => {
124	  let priorQuoteCount = 0;
125	  const results = scenario.steps.map((step) => {
126	    const result = quote(step, scenario.customer, priorQuoteCount);
127	    priorQuoteCount += 1;
128	    return result;
129	  });
130	  return { results };
131	};
