const followUpContractDiscount = (basePremium: number, priorQuoteCount: number): number =>
  priorQuoteCount > 0 ? basePremium * FOLLOW_UP_CONTRACT_DISCOUNT_RATE : 0;

const quote = (
  step: QuoteStep,
  customer: Scenario["customer"],
  priorQuoteCount: number,
): QuoteResult => {
  const basePremium = calculateBasePremium(step.items);
  const itemSurcharges = sumItemSpecificSurcharges(step.items);
  const premium = Math.ceil(
    basePremium +
      itemSurcharges +
      firstContractSurcharge(basePremium) -
      loyaltyDiscount(basePremium, customer.yearsWithMHPCO) -
      followUpContractDiscount(basePremium, priorQuoteCount) +
      PROCESSING_FEE,
  );
  return { premium };
};

export const runScenario = (scenario: Scenario): ScenarioResult => {
  let priorQuoteCount = 0;
  const results = scenario.steps.map((step) => {
    const result = quote(step, scenario.customer, priorQuoteCount);
    priorQuoteCount += 1;
    return result;
  });
  return { results };
};

