const followUpContractDiscount = (basePremium: number, isFollowUp: boolean): number =>
  isFollowUp ? basePremium * FOLLOW_UP_CONTRACT_DISCOUNT_RATE : 0;

const quote = (
  step: QuoteStep,
  customer: Scenario["customer"],
  isFollowUp: boolean,
): QuoteResult => {
  const basePremium = calculateBasePremium(step.items);
  const itemSurcharges = sumItemSpecificSurcharges(step.items);
  const premium = Math.ceil(
    basePremium +
      itemSurcharges +
      firstContractSurcharge(basePremium) -
      loyaltyDiscount(basePremium, customer.yearsWithMHPCO) -
      followUpContractDiscount(basePremium, isFollowUp) +
      PROCESSING_FEE,
  );
  return { premium };
};

export const runScenario = (scenario: Scenario): ScenarioResult => {
  const results = scenario.steps.map((step, index) =>
    quote(step, scenario.customer, index > 0),
  );
  return { results };
};
